INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (209, 89043, 5, 494, '我对鲁迅之观感', '在这个时代，大侃特侃李敖、王朔是受人欢迎的，要不谈谈金庸还大有市场，至于鲁迅就有很多人要嗤之以鼻。经济高速发展的今天，备受压力催残的人们更倾心于一些闲适的文章，如梁实秋的《雅舍小品》就曾经风靡一时，博得大家的会心一笑；或是看看冰心、林语堂的文章，其婉约、儒雅的文风使人入沐春风之中。然而一谈到鲁迅，就有很多人要从情感上加以排斥。
<br>
<br>一来鲁迅在文学史上的地位极高，有反骨的现代人很喜欢将原有的秩序打乱，反崇高成为流行一时的心态。确实有很多事物需要你用新的眼光来看待，但是否要将所有的事物全都否定而视之为有个性的表现，那最终是不是也要否定自己？二来鲁迅从不懂得含蓄为何物，他清醒看待人世，将社会中的万般丑态逐一洞察，以犀利的文笔作为武器与其黑暗挑战。文笔之犀利，如锋芒，如匕首，直刺许多人的痛处，难怪要有很多人跳脚，大骂鲁迅。这只能怪鲁迅太睿智，太“不识时务”了，与传统的中庸之风格格不入。三来大家看鲁迅的文章，就会发现鲁迅很多杂文都是批判这批判那，似乎有失文人儒雅的风格，骂人时如此尖酸刻薄又似乎有失厚道，但是我想正所谓一个铜板拍不响，这能完全怪罪鲁迅吗？鲁迅在《无花的蔷薇》中就曾说过“被毁则报，被誉则默，正是人情之常。谁能说人的左颊既受爱人接吻而不作一声，就得援此为例，必须默默地将右颊给仇人咬一口呢？”这是精彩的话，你只要将鲁迅视为正常的人就可以了，何况鲁迅也从来不把自己标榜为神或是全人类的救世主！
<br>
<br>鲁迅被定格为我国伟大的文学家、思想家、革命家，抛开这个框架，将鲁迅还原为人，用人的心态而不是神的标准来评价鲁迅，也许会有一番新的境地。当时正是白话文兴起的时代，鲁迅的文笔未见得优雅得体，或许还不如他弟弟周作人来得优游自在。但是鲁迅是用心来写作的，思想的博大精深，言辞的激越恳切每每令我叹服。对历史的深刻洞察，对人性的精彩剖析，其入木三分之处，常让我拍案叫绝。比如鲁迅对现代史的看法就让人在哈哈大笑之余，感到浓墨的悲哀。他认为历史就是一套戏法不断重演的历史，却也总有人看，真的是成了不死不活的东西。我觉得鲁迅的悲哀是先醒者的悲哀，他不甘继续沉睡下去，目睹沉睡者比清醒者多的现状，他不曾放弃，他呐喊、狂呼，希望能唤醒更多的民众。也许现状未曾达到他的理想，但我认为鲁迅的执着无悔、毅然决然就如同古代的夸父逐日一样都是值得敬仰的，他们都是大写的人！
<br>
<br>在理想、信仰被排拒的今天，鲁迅不受一些人欢迎的现状也就纯属正常了。说实话，中学时的我对鲁迅也是挺逆反的，为什么？因为只要是鲁迅的文章，就意味着有一大堆的笔记等着你去抄，有深刻的理论需要你去生吞活剥。当时的我非但不感兴趣，还相当感冒，我还不如去读读柳永、李清照的诗词来得惬意畅快！中学课文中有关鲁迅的文章至今还印象深刻就要属那篇《故乡》了，从没想过什么反封建的主题，倒是少年闰土可爱的形象至今还历历在目。那样的夜色，那样的人，整个画面是鲜活灵动的。至于成年的闰土我倒印象淡薄了，只是为他和迅哥儿年少纯真的友谊经过岁月的冲刷而面目全非感到几分遗憾、惋惜，再加上整个村庄的荒瘠败落，都让人产生一种“物是人非事事休”的悲凉感。
<br>
<br>所以有时我也常想一种米养千种人，同一篇文章不同的人读来有不同的观感，大家何不畅所欲言，也许百花齐放才是真正的春天。闲适冲淡未尝不是一件坏事，犀利泼辣也别有一番滋味。现今的我们可以品茗聊天，闲话家常，优游自在是大家所乐见。但身处战火纷飞、狼烟四起的时代，脑袋随时有搬家的危险，再大谈闲适、平和略嫌有些怪异，或是想效仿古人来个“壮士饥餐胡虏肉，笑谈渴饮匈奴血”，只是那些名人雅士喝的不是茶而是人血时，又有一番怎样的感受呢？
<br>
<br>鲁迅，如果你活到了现在，是否会雍容平和些？我想以你的个性，对一些不正常的社会现象还是会大肆抨击，也还是难免会树立许多敌人。世上就是有这些天生不讨好的人，不懂得“识事务者为俊杰”的人，也正因为有这些人，才有了社会的进步，文明的延续。对于不公平的对待，你无须埋怨，因为“你超越了他们，他们已不能/维系住你的向上，你的旷远”...', '在这个时代，大侃特侃李敖、王朔是受人欢迎的，要不谈谈金庸还大有市场，至于鲁迅就有很多人要嗤之以鼻。经济高速发展的今天，备受压力催残的人们更倾心于一些闲适的文章，如梁实秋的《雅舍小品》就曾经风靡一时，博得大家的会心一笑；或是看看冰心、林语堂的文章，其婉约、儒雅的文风使人入沐春风之中。然而一谈到鲁迅，就有很多人要从情感上加以排斥。

一来鲁迅在文学史上的地位极高，有反骨的现代人很喜欢将原有的秩序打乱，反崇高成为流行一时的心态。确实有很多事物需要你用新的眼光来看待，但是否要将所有的事物全都否定而视之为有个性的表现，那最终是不是也要否定自己？二来鲁迅从不懂得含蓄为何物，他清醒看待人世，将社会中的万般丑态逐一洞察，以犀利的文笔作为武器与其黑暗挑战。文笔之犀利，如锋芒，如匕首，直刺许多人的痛处，难怪要有很多人跳脚，大骂鲁迅。这只能怪鲁迅太睿智，太“不识时务”了，与传统的中庸之风格格不入。三来大家看鲁迅的文章，就会发现鲁迅很多杂文都是批判这批判那，似乎有失文人儒雅的风格，骂人时如此尖酸刻薄又似乎有失厚道，但是我想正所谓一个铜板拍不响，这能完全怪罪鲁迅吗？鲁迅在《无花的蔷薇》中就曾说过“被毁则报，被誉则默，正是人情之常。谁能说人的左颊既受爱人接吻而不作一声，就得援此为例，必须默默地将右颊给仇人咬一口呢？”这是精彩的话，你只要将鲁迅视为正常的人就可以了，何况鲁迅也从来不把自己标榜为神或是全人类的救世主！

鲁迅被定格为我国伟大的文学家、思想家、革命家，抛开这个框架，将鲁迅还原为人，用人的心态而不是神的标准来评价鲁迅，也许会有一番新的境地。当时正是白话文兴起的时代，鲁迅的文笔未见得优雅得体，或许还不如他弟弟周作人来得优游自在。但是鲁迅是用心来写作的，思想的博大精深，言辞的激越恳切每每令我叹服。对历史的深刻洞察，对人性的精彩剖析，其入木三分之处，常让我拍案叫绝。比如鲁迅对现代史的看法就让人在哈哈大笑之余，感到浓墨的悲哀。他认为历史就是一套戏法不断重演的历史，却也总有人看，真的是成了不死不活的东西。我觉得鲁迅的悲哀是先醒者的悲哀，他不甘继续沉睡下去，目睹沉睡者比清醒者多的现状，他不曾放弃，他呐喊、狂呼，希望能唤醒更多的民众。也许现状未曾达到他的理想，但我认为鲁迅的执着无悔、毅然决然就如同古代的夸父逐日一样都是值得敬仰的，他们都是大写的人！

在理想、信仰被排拒的今天，鲁迅不受一些人欢迎的现状也就纯属正常了。说实话，中学时的我对鲁迅也是挺逆反的，为什么？因为只要是鲁迅的文章，就意味着有一大堆的笔记等着你去抄，有深刻的理论需要你去生吞活剥。当时的我非但不感兴趣，还相当感冒，我还不如去读读柳永、李清照的诗词来得惬意畅快！中学课文中有关鲁迅的文章至今还印象深刻就要属那篇《故乡》了，从没想过什么反封建的主题，倒是少年闰土可爱的形象至今还历历在目。那样的夜色，那样的人，整个画面是鲜活灵动的。至于成年的闰土我倒印象淡薄了，只是为他和迅哥儿年少纯真的友谊经过岁月的冲刷而面目全非感到几分遗憾、惋惜，再加上整个村庄的荒瘠败落，都让人产生一种“物是人非事事休”的悲凉感。

所以有时我也常想一种米养千种人，同一篇文章不同的人读来有不同的观感，大家何不畅所欲言，也许百花齐放才是真正的春天。闲适冲淡未尝不是一件坏事，犀利泼辣也别有一番滋味。现今的我们可以品茗聊天，闲话家常，优游自在是大家所乐见。但身处战火纷飞、狼烟四起的时代，脑袋随时有搬家的危险，再大谈闲适、平和略嫌有些怪异，或是想效仿古人来个“壮士饥餐胡虏肉，笑谈渴饮匈奴血”，只是那些名人雅士喝的不是茶而是人血时，又有一番怎样的感受呢？

鲁迅，如果你活到了现在，是否会雍容平和些？我想以你的个性，对一些不正常的社会现象还是会大肆抨击，也还是难免会树立许多敌人。世上就是有这些天生不讨好的人，不懂得“识事务者为俊杰”的人，也正因为有这些人，才有了社会的进步，文明的延续。对于不公平的对待，你无须埋怨，因为“你超越了他们，他们已不能/维系住你的向上，你的旷远”...', NULL, '2001-01-28 18:23:00', 16, '20020113034331_bbsid_89043_board_5_c5d08b7b56.html', '20020113034331');
